--
-- Migration 010: State Authority protocol (Plan 2)
--   * portauth_state_authorities: registry of external state authorities
--   * portauth_state_proofs: durable record of accepted (signed) state proofs

CREATE TABLE IF NOT EXISTS portauth_state_authorities (
  id              BIGSERIAL PRIMARY KEY,
  authority_id    TEXT NOT NULL UNIQUE,
  base_url        TEXT NOT NULL,
  jwks_uri        TEXT,
  description     TEXT,
  active          BOOLEAN NOT NULL DEFAULT TRUE,
  added_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_portauth_state_authorities_active
  ON portauth_state_authorities (active);

CREATE TABLE IF NOT EXISTS portauth_state_proofs (
  id              BIGSERIAL PRIMARY KEY,
  authority_id    TEXT NOT NULL REFERENCES portauth_state_authorities(authority_id) ON DELETE CASCADE,
  counter_key     TEXT NOT NULL,
  window_start    TIMESTAMPTZ NOT NULL,
  metric          TEXT NOT NULL,
  reported_value  NUMERIC NOT NULL,
  proof_jws       TEXT NOT NULL,
  proof_issued_at TIMESTAMPTZ NOT NULL,
  consumed_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  request_id      TEXT,
  UNIQUE (authority_id, counter_key, window_start, proof_issued_at)
);

CREATE INDEX IF NOT EXISTS idx_portauth_state_proofs_lookup
  ON portauth_state_proofs (counter_key, window_start);
